import json
import re

business_data = locals()['var_function-call-1169158051281855924']['results']

wifi_businesses = []
for business in business_data:
    if 'attributes' in business and business['attributes'] and 'WiFi' in business['attributes']:
        wifi_status = business['attributes']['WiFi']
        if wifi_status == "u'free'" or wifi_status == "u'paid'":
            wifi_businesses.append(business)

business_states = {}
for business in wifi_businesses:
    description = business.get('description', '')
    match = re.search(r', ([A-Z]{2})', description)
    if match:
        state = match.group(1)
        business_id = business['business_id'].replace('businessid_', 'businessref_')
        if state not in business_states:
            business_states[state] = {'count': 0, 'business_ids': []}
        business_states[state]['count'] += 1
        business_states[state]['business_ids'].append(business_id)

# Find the state with the highest number of WiFi businesses
highest_state = None
highest_count = 0
for state, data in business_states.items():
    if data['count'] > highest_count:
        highest_count = data['count']
        highest_state = state

result = {'highest_state': highest_state, 'highest_count': highest_count, 'business_ids': business_states[highest_state]['business_ids'] if highest_state else []}
print('__RESULT__:')
print(json.dumps(result))

